htmlform.script:
        jQuery(document).ready(function($) {
            // Setup TB Option Cards (Mini Rectangular)
            function setupTbOptionCards() {
                $('.tb-option-card').each(function() {
                    var $card = $(this);
                    var $checkbox = $card.find('input[type="checkbox"]');

                    // Initial state
                    if ($checkbox.is(':checked')) {
                        $card.addClass('selected');
                    }

                    // Change handler
                    $checkbox.on('change', function() {
                        if ($(this).is(':checked')) {
                            $card.addClass('selected');
                        } else {
                            $card.removeClass('selected');
                        }
                    });

                    // Click on card triggers checkbox (if not clicking the checkbox/label/input itself)
                    $card.on('click', function(e) {
                        if (!$(e.target).is('input, label, textarea')) {
                            $checkbox.prop('checked', !$checkbox.prop('checked')).trigger('change');
                        }
                    });
                });
            }
            setupTbOptionCards();

            // TB Screening Logic
            var checkTBSymptoms = function() {
                var anySymptom = false;
                $('.tb-symptom input').each(function() {
                    if ($(this).is(':checked')) anySymptom = true;
                });

                if (anySymptom) {
                    $('#tb-warning').slideDown();
                } else {
                    $('#tb-warning').slideUp();
                }
            };

            // Bind to change events
            $('.tb-symptom input').change(checkTBSymptoms);

            // Initial check
            setTimeout(checkTBSymptoms, 500);

            // TB Surveillance alerts
            var updateTbAlerts = function() {
                $('#surveillance-tb .tb-bacilloscopie-field').each(function() {
                    var field = $(this);
                    var radios = field.find('input[type="radio"]');
                    var alert = field.find('.tb-alert');
                    var positive = false;

                    radios.each(function() {
                        var input = $(this);
                        if (input.is(':checked')) {
                            var val = input.val() || '';
                            if (val.indexOf('703') === 0) {
                                positive = true;
                            }
                        }
                    });

                    if (positive) {
                        alert.show();
                    } else {
                        alert.hide();
                    }
                });
            };

            $('#surveillance-tb').on('change', 'input[type="radio"]', function() {
                updateTbAlerts();
            });
            setTimeout(updateTbAlerts, 800);

            if (!document.querySelector('meta[name="viewport"]')) {
                $('head').append('');
            }

            $('.toggle-trigger').on('click', function(e) {
                e.preventDefault();
                var target = $(this).data('target');
                var $this = $(this);

                // Close others and reset their styles
                $('.section-content').not(target).slideUp('fast');
                $('.toggle-trigger').not($this).removeClass('active').find('.toggle-icon').removeClass('rotated');

                // Toggle current
                $(target).slideToggle('fast');
                $this.toggleClass('active');
                $this.find('.toggle-icon').toggleClass('rotated');
            });

            var applyDiagnosisState = function(input) {
                var target = input.closest('.diagnosis-row').find('.diagnosis-details');
                if (input.is(':checked')) {
                    target.show();
                } else {
                    target.hide();
                }
            };

            $('.diagnosis-trigger input').each(function() {
                applyDiagnosisState($(this));
            }).on('change', function() {
                var input = $(this);
                var target = input.closest('.diagnosis-row').find('.diagnosis-details');
                if (input.is(':checked')) {
                    target.slideDown();
                } else {
                    target.slideUp();
                }
            });

            var updateLocation = function() {
                var locType = getValue('locationTypeValue.value');
                if (locType == 'Le site même' || locType == 'Site autre que celui du patient') {
                    $('#locationValue').show();
                } else {
                    $('#locationValue').hide();
                }
            };

            if (getValue('locationTypeValue.value') == '') {
                setValue('locationTypeValue.value', 'Le site même');
            }
            updateLocation();
            $('#locationTypeValue').change(updateLocation);

            // Antecedents Enhancement Logic
            var sourceContainer = $('#antecedents-source');
            var dropdown = $('#antecedents-dropdown');
            var selectedContainer = $('#selected-antecedents-container');

            // Function to add antecedent (prevents duplicates)
            var addAntecedent = function(index, highlight) {
                // If this index is already in the selected list, do nothing
                if (selectedContainer.find('.selected-antecedent-item[data-index="' + index + '"]').length > 0) {
                    return;
                }

                // Find the corresponding obs group (may be in source or already wrapped)
                var $group = sourceContainer.find('.obs-group-item[data-index="' + index + '"]');

                // Create wrapper and mark with index
                var wrapper = $('
').attr('data-index', index);
                var content = $('
');
                var actions = $('
');

                // Buttons
                var upBtn = $('↑').click(function() {
                    var item = $(this).closest('.selected-antecedent-item');
                    item.prev().before(item);
                });
                var downBtn = $('↓').click(function() {
                    var item = $(this).closest('.selected-antecedent-item');
                    item.next().after(item);
                });
                var removeBtn = $('×').click(function() {
                    var item = $(this).closest('.selected-antecedent-item');
                    var grp = item.find('.obs-group-item');

                    // Uncheck input
                    grp.find('input[type="checkbox"], input[type="radio"]').prop('checked', false).change();
                    // Clear text inputs if any
                    grp.find('input[type="text"]').val('');

                    // Move group back to source
                    sourceContainer.append(grp);

                    // Remove wrapper
                    item.remove();
                });

                actions.append(upBtn).append(downBtn).append(removeBtn);

                // Move group to content
                content.append($group);

                // Check the input (find the checkbox inside the obsgroup)
                $group.find('input[type="checkbox"], input[type="radio"]').prop('checked', true).change();

                wrapper.append(content).append(actions);
                selectedContainer.append(wrapper);

                if (highlight) {
                    wrapper.addClass('highlight');
                    setTimeout(function() { wrapper.removeClass('highlight'); }, 1000);
                }
            };

            // Initialize Options
            sourceContainer.find('.obs-group-item').each(function(index) {
                var $group = $(this);
                // Extract label text
                var labelText = $group.text().trim();
                var $label = $group.find('label');
                if ($label.length > 0) {
                     // Clone label to avoid modifying DOM
                    labelText = $label.text().trim();
                } else {
                    // Try to clean up text if it contains the input
                     // Simple heuristic: get text content
                     labelText = $group.text().replace(/, précisez/g, '').trim();
                }

                // Create option
                if (labelText) {
                    var option = $('').val(index).text(labelText);
                    dropdown.append(option);
                }

                // Assign ID to group
                $group.attr('data-index', index);

                // Check if already selected (for edit mode)
                var $input = $group.find('input[type="checkbox"], input[type="radio"]');
                if ($input.is(':checked')) {
                    addAntecedent(index, false);
                }
            });

            // Add Button Click
            $('#add-antecedents-btn').click(function(e) {
                e.preventDefault();
                var selectedIndices = dropdown.val();
                if (selectedIndices) {
                    $.each(selectedIndices, function(i, index) {
                        addAntecedent(index, true);
                    });
                    dropdown.val([]); // Clear selection
                }
            });

            // Motifs de consultation Enhancement Logic
            var motifsSource = $('#motifs-source');
            var motifsDropdown = $('#motifs-dropdown');
            var motifsSelected = $('#selected-motifs-container');

            var addMotif = function(index, highlight) {
                if (motifsSelected.find('.selected-antecedent-item[data-motif-index="' + index + '"]').length > 0) {
                    return;
                }

                var item = motifsSource.find('.motif-item[data-index="' + index + '"]');
                if (!item.length) {
                    return;
                }

                var wrapper = $('
').attr('data-motif-index', index);
                var content = $('
');
                var actions = $('
');

                var removeBtn = $('×').click(function() {
                    var w = $(this).closest('.selected-antecedent-item');
                    var srcItem = w.find('.motif-item');

                    srcItem.find('input[type="checkbox"], input[type="radio"]').prop('checked', false).change();
                    srcItem.find('input[type="text"]').val('');

                    motifsSource.append(srcItem);
                    w.remove();
                });

                actions.append(removeBtn);
                content.append(item);

                item.find('input[type="checkbox"], input[type="radio"]').prop('checked', true).change();

                wrapper.append(content).append(actions);
                motifsSelected.append(wrapper);

                if (highlight) {
                    wrapper.addClass('highlight');
                    setTimeout(function() { wrapper.removeClass('highlight'); }, 1000);
                }
            };

            motifsSource.find('.motif-item').each(function(index) {
                var group = $(this);
                group.attr('data-index', index);

                var labelText = group.text().trim();
                var labelEl = group.find('label').first();
                if (labelEl.length > 0) {
                    labelText = labelEl.text().trim();
                }

                if (labelText) {
                    motifsDropdown.append($('').val(index).text(labelText));
                }

                var input = group.find('input[type="checkbox"], input[type="radio"]');
                if (input.is(':checked')) {
                    addMotif(index, false);
                }
            });

            $('#add-motifs-btn').click(function(e) {
                e.preventDefault();
                var selectedIndices = motifsDropdown.val();
                if (selectedIndices) {
                    $.each(selectedIndices, function(i, index) {
                        addMotif(index, true);
                    });
                    motifsDropdown.val([]);
                }
            });

            var diagnosisSource = $('#diagnosis-source');
            var diagnosisDropdown = $('#diagnosis-dropdown');
            var diagnosisSelected = $('#selected-diagnosis-container');
            var diagnosisDragItem = null;

            var attachDiagnosisDragHandlers = function(wrapper) {
                wrapper.attr('draggable', 'true');

                // Prevent drag start on inputs to allow normal interaction
                wrapper.on('mousedown', function(e) {
                    if ($(e.target).is('input, select, textarea, label')) {
                         wrapper.attr('draggable', 'false');
                    } else {
                         wrapper.attr('draggable', 'true');
                    }
                });

                wrapper.on('mouseup', function(e) {
                     wrapper.attr('draggable', 'true');
                });

                wrapper.on('dragstart', function(e) {
                    diagnosisDragItem = $(this);
                    if (e.originalEvent && e.originalEvent.dataTransfer) {
                        e.originalEvent.dataTransfer.effectAllowed = 'move';
                    }
                });
                wrapper.on('dragend', function() {
                    diagnosisDragItem = null;
                    wrapper.attr('draggable', 'true');
                });
                wrapper.on('dragover', function(e) {
                    e.preventDefault();
                    if (e.originalEvent && e.originalEvent.dataTransfer) {
                        e.originalEvent.dataTransfer.dropEffect = 'move';
                    }
                });
                wrapper.on('drop', function(e) {
                    e.preventDefault();
                    if (!diagnosisDragItem || diagnosisDragItem[0] === this) {
                        return;
                    }
                    var target = $(this);
                    if (target.index() < diagnosisDragItem.index()) {
                        target.before(diagnosisDragItem);
                    } else {
                        target.after(diagnosisDragItem);
                    }
                });
            };

            var addDiagnosis = function(index, highlight) {
                if (diagnosisSelected.find('.selected-diagnosis-item[data-index="' + index + '"]').length > 0) {
                    return;
                }
                var item = diagnosisSource.find('.diagnosis-row[data-index="' + index + '"]');
                if (!item.length) {
                    return;
                }
                var wrapper = $('
').attr('data-index', index);
                var dragHandle = $('
⋮⋮');
                var content = $('
');
                var actions = $('
');

                var upBtn = $('↑').click(function() {
                    var row = $(this).closest('.selected-diagnosis-item');
                    row.prev().before(row);
                });
                var downBtn = $('↓').click(function() {
                    var row = $(this).closest('.selected-diagnosis-item');
                    row.next().after(row);
                });
                var removeBtn = $('×').click(function() {
                    var row = $(this).closest('.selected-diagnosis-item');
                    var src = row.find('.diagnosis-row');
                    src.find('input[type="checkbox"], input[type="radio"]').prop('checked', false).change();
                    src.find('input[type="text"]').val('');
                    src.find('textarea').val('');
                    src.find('.diagnosis-details').hide();
                    diagnosisSource.append(src);
                    row.remove();
                });

                actions.append(upBtn).append(downBtn).append(removeBtn);
                content.append(item);

                var triggerInput = item.find('.diagnosis-trigger input');
                if (triggerInput.length) {
                    triggerInput.prop('checked', true).change();
                }

                wrapper.append(dragHandle).append(content).append(actions);
                diagnosisSelected.append(wrapper);
                attachDiagnosisDragHandlers(wrapper);

                if (highlight) {
                    wrapper.addClass('highlight');
                    setTimeout(function() { wrapper.removeClass('highlight'); }, 1000);
                }
            };

            diagnosisSource.find('.diagnosis-row').each(function(index) {
                var row = $(this);
                row.attr('data-index', index);
                var labelText = row.find('.diagnosis-trigger').text().trim();
                if (!labelText) {
                    labelText = row.text().trim();
                }
                if (labelText) {
                    diagnosisDropdown.append($('').val(index).text(labelText));
                }
                var input = row.find('.diagnosis-trigger input');
                if (input.is(':checked')) {
                    addDiagnosis(index, false);
                }
            });

            $('#add-diagnosis-btn').click(function(e) {
                e.preventDefault();
                var selectedIndices = diagnosisDropdown.val();
                if (selectedIndices) {
                    $.each(selectedIndices, function(i, index) {
                        addDiagnosis(index, true);
                    });
                    diagnosisDropdown.val([]);
                }
            });

            var calculateBmi = function(wt, ht) {
                var bmi = null;
                if (wt && ht) {
                    bmi = wt / ((ht / 100) * (ht / 100));
                }
                return bmi;
            };

            var calculatePbpc = function(pb, pc) {
                var pbpc = null;
                if (pb && pc) {
                    pbpc = pb / pc;
                }
                return pbpc;
            };

            var updateBmi = function() {
                var wt = htmlForm.getValueIfLegal('weight.value');
                var ht = htmlForm.getValueIfLegal('height.value');

                var bmi = calculateBmi(wt, ht);

                if (bmi == null || isNaN(bmi)) {
                    jQuery('#calculated-bmi-wrapper').hide();
                } else {
                    jQuery('#no-calculated-bmi').hide();
                    jQuery('#calculated-bmi-wrapper').show();
                    jQuery('#calculated-bmi').html(bmi.toFixed(1));
                    jQuery('#hidden-calculated-bmi').val(bmi.toFixed(1));
                }
            };

            var updatePbpc = function() {
                var pb = htmlForm.getValueIfLegal('pb.value');
                var pc = htmlForm.getValueIfLegal('pc.value');

                var pbpc = calculatePbpc(pb, pc);

                if (pbpc == null || isNaN(pbpc)) {
                    jQuery('#calculated-pbpc-wrapper').hide();
                } else {
                    jQuery('#no-calculated-pbpc').hide();
                    jQuery('#calculated-pbpc-wrapper').show();
                    jQuery('#calculated-pbpc').html(pbpc.toFixed(1));
                }
            };

            jQuery('htmlform').each(function(index, form) {
                jQuery(form).find('#calculated-bmi-continue').hide();
                jQuery(form).find('#no-calculated-bmi').hide();

                var wt = jQuery(form).find('#weight').find('.value').text();
                var ht = jQuery(form).find('#height').find('.value').text();

                var bmi = calculateBmi(wt, ht);

                if (bmi != null && !isNaN(bmi)) {
                    jQuery(form).find('#calculated-bmi-wrapper').show();
                    jQuery(form).find('#calculated-bmi').html(bmi.toFixed(1));
                    jQuery(form).find('#calculated-bmi-view').html(bmi.toFixed(1));
                    jQuery(form).find('#hidden-calculated-bmi').val(bmi.toFixed(1));
                }
            });

            jQuery('#calculated-bmi-wrapper').each(function() {
                jQuery('#calculated-bmi-wrapper').hide();

                getField('weight.value').change(updateBmi);
                getField('height.value').change(updateBmi);

                updateBmi();
            });

            // CALCULET PB / PC
		jQuery('htmlform').each(function(index, form) {
		jQuery(form).find('#calculated-pbpc-continue').hide();
		jQuery(form).find('#no-calculated-pbpc').hide();

		var pb = jQuery(form).find('#pb').find('.value').text();
		var pc = jQuery(form).find('#pc').find('.value').text();

		var pbpc = calculatePbpc(pb, pc);

		if (pbpc != null && !isNaN(pbpc)) {
		jQuery(form).find('#calculated-pbpc-wrapper').show();
		jQuery(form).find('#calculated-pbpc').html(pbpc.toFixed(1));
		jQuery(form).find('#hidden-calculated-pbpc').val(pbpc.toFixed(1));
		}
		});

		jQuery('#calculated-pbpc-wrapper').each(function(){
		jQuery('#calculated-pbpc-wrapper').hide();
		getField('pb.value').change(updatePbpc)
		getField('pc.value').change(updatePbpc);
		updatePbpc();
		});

            var initVaccinationRow = function(row) {
                var header = row.find('.vaccination-entry-header');
                header.off('click').on('click', function(e) {
                    if (jQuery(e.target).closest('.remove-vaccination-btn').length) {
                        return;
                    }
                    row.toggleClass('active');
                });
            };

            var updateVaccinationSummary = function(index) {
                var row = jQuery('.vaccination-entry[data-row="' + index + '"]');
                if (!row.length) {
                    return;
                }
                var name = htmlForm.getValueIfLegal('vaccination_name' + index + '.value');
                var date = htmlForm.getValueIfLegal('vaccination_date' + index + '_dose1.value');
                var nameSpan = row.find('.vaccination-entry-name-summary');
                var dateSpan = row.find('.vaccination-entry-date-summary');
                nameSpan.text(name ? name : '');
                dateSpan.text(date ? date : '');
            };

            var initVaccinationDoseRows = function(row) {
                var idx = row.data('row');
                if (!idx) {
                    return;
                }
                for (var d = 1; d <= 5; d++) {
                    var doseRow = row.find('.vaccination-dose-row[data-dose="' + d + '"]');
                    if (!doseRow.length) {
                        continue;
                    }
                    var dateVal = htmlForm.getValueIfLegal('vaccination_date' + idx + '_dose' + d + '.value');
                    var noteVal = htmlForm.getValueIfLegal('vaccination_note' + idx + '_dose' + d + '.value');
                    if (d === 1) {
                        doseRow.show();
                    } else if (dateVal || noteVal) {
                        doseRow.show();
                    } else {
                        doseRow.hide();
                    }
                }
                var addBtn = row.find('.add-dose-btn');
                addBtn.off('click').on('click', function(e) {
                    e.preventDefault();
                    var next = row.find('.vaccination-dose-row').filter(function() {
                        var dose = jQuery(this).data('dose');
                        return dose && dose > 1 && !jQuery(this).is(':visible');
                    }).first();
                    if (next.length) {
                        next.show();
                    } else if (jQuery().toastmessage) {
                        jQuery().toastmessage('showNoticeToast', 'Nombre maximal de doses atteint');
                    }
                });
            };

            jQuery('.vaccination-entry').each(function() {
                var row = jQuery(this);
                var idx = row.data('row');
                initVaccinationRow(row);
                initVaccinationDoseRows(row);
                if (!idx) {
                    return;
                }
                var name = htmlForm.getValueIfLegal('vaccination_name' + idx + '.value');
                var date = htmlForm.getValueIfLegal('vaccination_date' + idx + '_dose1.value');
                var notes = htmlForm.getValueIfLegal('vaccination_notes' + idx + '.value');
                var hasAnyDose = false;
                for (var d = 1; d <= 5; d++) {
                    var doseDate = htmlForm.getValueIfLegal('vaccination_date' + idx + '_dose' + d + '.value');
                    var doseNote = htmlForm.getValueIfLegal('vaccination_note' + idx + '_dose' + d + '.value');
                    if (doseDate || doseNote) {
                        hasAnyDose = true;
                        break;
                    }
                }
                if (name || notes || hasAnyDose || date) {
                    row.show();
                    row.attr('data-active', 'true');
                    row.addClass('active');
                }
            });

            for (var i = 1; i <= 5; i++) {
                (function(idx) {
                    var nameField = getField('vaccination_name' + idx + '.value');
                    var dateField = getField('vaccination_date' + idx + '_dose1.value');
                    if (nameField && nameField.length) {
                        nameField.change(function() {
                            updateVaccinationSummary(idx);
                        });
                    }
                    if (dateField && dateField.length) {
                        dateField.change(function() {
                            updateVaccinationSummary(idx);
                        });
                    }
                    updateVaccinationSummary(idx);
                })(i);
            }

            jQuery('#add-vaccination-btn').click(function(e) {
                e.preventDefault();
                var next = jQuery('.vaccination-entry').filter(function() {
                    return jQuery(this).attr('data-active') !== 'true';
                }).first();
                if (next.length) {
                    next.show();
                    next.attr('data-active', 'true');
                    next.addClass('active');
                } else if (jQuery().toastmessage) {
                    jQuery().toastmessage('showNoticeToast', 'Nombre maximal de vaccinations atteint');
                }
            });

            jQuery('#vaccination-section').on('click', '.remove-vaccination-btn', function(e) {
                e.preventDefault();
                var row = jQuery(this).closest('.vaccination-entry');
                var idx = row.data('row');
                if (idx) {
                    var simpleFields = ['vaccination_name', 'vaccination_notes'];
                    jQuery.each(simpleFields, function(i, base) {
                        var field = getField(base + idx + '.value');
                        if (field && field.length) {
                            field.val('');
                        }
                        var error = getField(base + idx + '.error');
                        if (error && error.length) {
                            error.html('');
                        }
                    });
                    for (var d = 1; d <= 5; d++) {
                        var dateField = getField('vaccination_date' + idx + '_dose' + d + '.value');
                        if (dateField && dateField.length) {
                            dateField.val('');
                        }
                        var dateError = getField('vaccination_date' + idx + '_dose' + d + '.error');
                        if (dateError && dateError.length) {
                            dateError.html('');
                        }
                        var noteField = getField('vaccination_note' + idx + '_dose' + d + '.value');
                        if (noteField && noteField.length) {
                            noteField.val('');
                        }
                        var noteError = getField('vaccination_note' + idx + '_dose' + d + '.error');
                        if (noteError && noteError.length) {
                            noteError.html('');
                        }
                    }
                }
                row.removeClass('incomplete active');
                row.hide();
                row.attr('data-active', 'false');
            });

            jQuery('#vaccination-section').on('click', '.remove-dose-btn', function(e) {
                e.preventDefault();
                var doseRow = jQuery(this).closest('.vaccination-dose-row');
                var row = jQuery(this).closest('.vaccination-entry');
                var idx = row.data('row');
                var dose = doseRow.data('dose');
                if (idx && dose) {
                    var dateField = getField('vaccination_date' + idx + '_dose' + dose + '.value');
                    if (dateField && dateField.length) {
                        dateField.val('');
                    }
                    var dateError = getField('vaccination_date' + idx + '_dose' + dose + '.error');
                    if (dateError && dateError.length) {
                        dateError.html('');
                    }
                    var noteField = getField('vaccination_note' + idx + '_dose' + dose + '.value');
                    if (noteField && noteField.length) {
                        noteField.val('');
                    }
                    var noteError = getField('vaccination_note' + idx + '_dose' + dose + '.error');
                    if (noteError && noteError.length) {
                        noteError.html('');
                    }
                }
                doseRow.hide();
            });

            // Supplementation Dynamic Logic
            jQuery('.supplementation-doses').on('click', '.add-dose-btn', function(e) {
                e.preventDefault();
                var container = jQuery(this).closest('.supplementation-doses');
                var next = container.find('.supplementation-dose-row:hidden').first();
                if (next.length) {
                    next.slideDown();
                } else {
                    if (jQuery().toastmessage) {
                        jQuery().toastmessage('showNoticeToast', 'Nombre maximal de dates atteint');
                    }
                }
            });

            jQuery('.supplementation-doses').on('click', '.remove-dose-btn', function(e) {
                e.preventDefault();
                var row = jQuery(this).closest('.supplementation-dose-row');

                // Clear inputs
                row.find('input').val('');
                row.find('.error').html(''); 

                row.slideUp();
            });

            var setupTbTreatmentResultCards = function() {
                var container = jQuery('#resultat-tb');
                if (!container.length) {
                    return;
                }
                var obsWrapper = container.find('.tb-result-obs');
                if (!obsWrapper.length) {
                    return;
                }
                var radios = obsWrapper.find('input[type="radio"]');
                if (!radios.length) {
                    return;
                }
                var configs = [
                    { title: 'Guéri', subtitle: 'Traitement complété avec succès' },
                    { title: 'Traitement Terminé', subtitle: 'Traitement complété' },
                    { title: 'Abandon', subtitle: 'Patient a abandonné le traitement' },
                    { title: 'Transféré', subtitle: 'Transféré vers un autre établissement' },
                    { title: 'Décédé', subtitle: 'Patient décédé' }
                ];
                var group = jQuery('
');
                radios.each(function(index) {
                    var cfg = configs[index] || {};
                    var card = jQuery('
');
                    var main = jQuery('
');
                    var title = jQuery('
').text(cfg.title || '');
                    var subtitle = jQuery('
').text(cfg.subtitle || '');
                    main.append(title).append(subtitle);
                    var status = jQuery('
').text('✔');
                    card.append(main).append(status);
                    card.data('radio-index', index);
                    group.append(card);
                    card.on('click', function() {
                        var idx = jQuery(this).data('radio-index');
                        radios.prop('checked', false);
                        var target = radios.eq(idx);
                        target.prop('checked', true).trigger('change');
                        group.find('.tb-result-card').removeClass('selected');
                        jQuery(this).addClass('selected');
                    });
                });
                obsWrapper.after(group);
                obsWrapper.addClass('tb-result-obs-hidden');
                var initialIndex = -1;
                radios.each(function(i) {
                    if (jQuery(this).is(':checked')) {
                        initialIndex = i;
                    }
                });
                if (initialIndex >= 0) {
                    group.find('.tb-result-card').eq(initialIndex).addClass('selected');
                }
            };

            setupTbTreatmentResultCards();

            var validateVaccinations = function() {
                var valid = true;
                jQuery('#vaccination-error').text('');
                jQuery('.vaccination-entry').removeClass('incomplete');
                jQuery('.vaccination-entry').each(function() {
                    var row = jQuery(this);
                    if (!row.is(':visible')) {
                        return;
                    }
                    var idx = row.data('row');
                    if (!idx) {
                        return;
                    }
                    var name = htmlForm.getValueIfLegal('vaccination_name' + idx + '.value');
                    var date = htmlForm.getValueIfLegal('vaccination_date' + idx + '_dose1.value');
                    var notes = htmlForm.getValueIfLegal('vaccination_notes' + idx + '.value');
                    var hasAnyDose = false;
                    for (var d = 1; d <= 5; d++) {
                        var doseDate = htmlForm.getValueIfLegal('vaccination_date' + idx + '_dose' + d + '.value');
                        var doseNote = htmlForm.getValueIfLegal('vaccination_note' + idx + '_dose' + d + '.value');
                        if (doseDate || doseNote) {
                            hasAnyDose = true;
                            break;
                        }
                    }
                    var hasData = !!(name || date || notes || hasAnyDose);
                    if (hasData && (!name || !date)) {
                        row.addClass('incomplete');
                        valid = false;
                    }
                });
                if (!valid) {
                    var message = "Compléter le nom du vaccin et la date pour chaque vaccination saisie ou supprimer l'entrée incomplète.";
                    jQuery('#vaccination-error').text(message);
                    if (jQuery().toastmessage) {
                        jQuery().toastmessage('showErrorToast', message);
                    }
                }
                return valid;
            };

            if (typeof beforeSubmit !== 'undefined') {
                beforeSubmit.push(function() {
                    return validateVaccinations();
                });
            }
        });

